-- SQL Server TRY/CATCH Error Handling
BEGIN TRY
    DECLARE @numerator   INT = 100;
    DECLARE @denominator INT = 0;
    DECLARE @result      INT;

    -- This will throw a divide-by-zero error
    SET @result = @numerator / @denominator;

    SELECT @result AS Result;
END TRY
BEGIN CATCH
    DECLARE @ErrMsg   NVARCHAR(4000) = ERROR_MESSAGE();
    DECLARE @ErrNum   INT            = ERROR_NUMBER();
    DECLARE @ErrSev   INT            = ERROR_SEVERITY();
    DECLARE @ErrState INT            = ERROR_STATE();

    PRINT 'Caught error #' + CAST(@ErrNum AS NVARCHAR)
        + ' Sev '   + CAST(@ErrSev AS NVARCHAR)
        + ' State ' + CAST(@ErrState AS NVARCHAR)
        + ': ' + @ErrMsg;

    -- Re-raise with original error number, severity, and state
    THROW;
END CATCH;

