-- PostgreSQL EXCEPTION Block Error Handling
-- Error handling lives inside a DO block or function body
DO $$
DECLARE
    v_numerator   INT := 100;
    v_denominator INT := 0;
    v_result      INT;
BEGIN
    -- This will raise a division_by_zero exception
    v_result := v_numerator / v_denominator;

    RAISE NOTICE 'Result: %', v_result;
EXCEPTION
    WHEN division_by_zero THEN
        RAISE NOTICE 'Caught error: SQLSTATE=%, Message=%',
                     SQLSTATE, SQLERRM;

        -- Re-raise the same error
        RAISE;
END;
$$;

