-- SQL Server: Raising custom errors with RAISERROR and THROW

-- RAISERROR (legacy, supports printf-style formatting)
DECLARE @CustomerID INT = -1;
IF @CustomerID < 0
BEGIN
    RAISERROR(
        'Invalid CustomerID %d: must be a positive integer.',
        16,   -- severity (1-25; 11-16 = user errors)
        1,    -- state (1-255)
        @CustomerID
    );
END;

-- THROW (SQL Server 2012+, preferred)
-- Error number must be >= 50000 for user-defined errors
DECLARE @OrderID  INT = -5;
DECLARE @ErrMsg   NVARCHAR(2048);

IF @OrderID <= 0
BEGIN
    SET @ErrMsg = CONCAT(
        'OrderID ', @OrderID,
        ' is invalid. Value must be greater than zero.'
    );
    THROW 50001, @ErrMsg, 1;
END;
